/* ─── Structures ───────────────────────────────────────────────────── */

typedef struct {
    WCHAR name[MAX_NAME];        /* display name (snake_case stripped, formatted) */
    WCHAR gh_path[MAX_PATH_APP]; /* repo-relative path, e.g. Part_Document_Scripts/foo.py */
    WCHAR description[256];      /* first docstring line from README or empty */
} Script;

typedef struct {
    WCHAR   name[MAX_NAME];          /* folder name as it appears in the repo */
    WCHAR   display[MAX_NAME];       /* formatted for the tab label */
    Script  scripts[MAX_SCRIPTS];
    int     count;
    bool    loaded;
} Folder;

typedef struct {
    WCHAR python_exe[MAX_PATH_APP];  /* full path to python.exe */
    WCHAR cache_dir[MAX_PATH_APP];   /* local dir where scripts are cached */
    WCHAR github_token[256];         /* optional PAT */
    bool  download_before_run;       /* fetch latest before executing */
    bool  show_console;              /* CREATE_NO_WINDOW vs normal */
} Settings;

typedef struct {
    /* Window handles */
    HWND  hwnd;
    HWND  hwnd_tab;
    HWND  hwnd_status;
    HWND  hwnd_scroll;      /* scrollable content area */

    /* Data */
    Folder   folders[MAX_FOLDERS];
    int      folder_count;
    int      active_tab;
    Settings cfg;

    /* GDI resources */
    HFONT    font_ui;
    HFONT    font_bold;
    HFONT    font_small;
    HBRUSH   br_bg;
    HBRUSH   br_panel;
    HBRUSH   br_toolbar;
    HBRUSH   br_btn;
    HBRUSH   br_btn_hot;
    HBRUSH   br_accent;

    /* State */
    bool     fetching;
    int      hot_btn;        /* IDC_SCRIPT_BTN_BASE + idx, or -1 */
    WCHAR    last_run[MAX_PATH_APP];
    int      scroll_y;
    int      scroll_max;
} AppState;

/* Global singleton – defined in main.c */
extern AppState g_app;

