/* util (inline helpers in app.h) */
static inline void Util_StripExt(WCHAR *s) {
    WCHAR *dot = wcsrchr(s, L'.');
    if (dot) *dot = L'\0';
}

static inline void Util_SnakeToTitle(WCHAR *s) {
    /* Replace underscores with spaces, capitalize after each */
    bool cap = true;
    for (WCHAR *p = s; *p; p++) {
        if (*p == L'_') { *p = L' '; cap = true; }
        else if (cap)   { *p = (WCHAR)towupper(*p); cap = false; }
    }
}

